import React, { useEffect, useRef, useState } from "react";
import { Rocket, Eye, History, Telescope, ChevronRight, ArrowRightToLine, Mountain, BookOpen } from "lucide-react";

// Constantes de datos con iconos
const mainSections = [
  {
    id: "objective",
    title: "OBJETIVO",
    displayTitle: "Objetivo",
    icon: ArrowRightToLine,
    body: ( 
      <p> 
        Preservamos, organizamos y exhibimos el patrimonio corporativo de empresas bolivianas con más de 40 años de trayectoria. 
        Digitalizamos archivos, certificamos hitos históricos y creamos narrativas vivas que honran el legado mientras inspiran 
        a la próxima generación de líderes empresariales. 
      </p> 
    ),
    image: '/media/historiapage/bolivia.jpg', 
  },
  {
    id: "mission",
    title: "MISIÓN",
    displayTitle: "Misión",
    icon: Mountain,
    body: ( 
      <p> 
        Proteger la memoria de la empresa boliviana mediante documentación rigurosa, narrativas históricas cuidadosas y diseño atemporal, 
        haciendo que el viaje de cada empresa sea accesible, verificable y bellamente preservado para el futuro. 
      </p> 
    ),
    image: '/media/historiapage/AGRO.jpg',
  },
  {
    id: "vision",
    title: "VISIÓN",
    displayTitle: "Visión",
    icon: Eye,
    body: ( 
      <p> 
        Un archivo nacional prestigioso donde la historia de la excelencia empresarial sea atesorada, sirviendo como referencia para 
        investigadores, emprendedores y familias que elevan el legado de la industria boliviana en el escenario mundial. 
      </p> 
    ),
    image: '/media/historiapage/flamingob.jpg',
  },
  {
    id: "origin",
    title: "ORIGEN",
    displayTitle: "Origen",
    icon: History,
    body: ( 
      <p> 
        Nacidos del compromiso con la memoria cultural, surgimos cuando historiadores, archiveros e innovadores se unieron alrededor 
        de una idea simple: si no documentamos nuestras empresas hoy, las generaciones futuras heredarán silencio donde debería haber legado. 
      </p> 
    ),
    image: '/media/historiapage/salarB.jpg', 
  },
];

// Datos de la línea de tiempo
const timelineData = [
  { 
    year: "1980s", 
    title: "ORIGEN",
    description: "Primeros archivos fundacionales recolectados en diversos sectores empresariales."
  },
  { 
    year: "1990s", 
    title: "",
    description: "Primeras alianzas público-privadas para la preservación histórica."
  },
  { 
    year: "2000s", 
    title: "",
    description: "Programa de digitalización y establecimiento de estándares de certificación."
  },
  { 
    year: "2010s", 
    title: "",
    description: "Exhibiciones interactivas y expansión institucional a nivel nacional."
  },
  { 
    year: "Actualidad", 
    title: "ORIGEN",
    description: "Una plataforma viva que conecta el legado con la innovación empresarial."
  },
];

const howItStartedSection = {
  id: "how",
  title: "NUESTRA HISTORIA",
  displayTitle: "Nuestra Historia",
  icon: BookOpen,
  body: (
    <div className="w-full">
      <div className="relative py-12">
        {/* Línea central para desktop */}
        <div className="hidden md:block absolute left-1/2 top-0 bottom-0 w-0.5 bg-gradient-to-b from-[#072D42]/30 via-[#072D42]/50 to-[#072D42]/30 transform -translate-x-1/2"></div>
        
        {/* Línea central para móvil */}
        <div className="block md:hidden absolute left-8 top-0 bottom-0 w-0.5 bg-gradient-to-b from-[#072D42]/30 via-[#072D42]/50 to-[#072D42]/30"></div>

        <div className="space-y-8 md:space-y-0">
          {timelineData.map((item, index) => (
            <div key={index} className="relative">
              {/* Contenedor para desktop */}
              <div className="hidden md:flex items-center justify-center w-full">
                {/* Lado izquierdo - años pares */}
                {index % 2 === 0 ? (
                  <>
                    <div className="w-2/5 pr-8 text-right">
                      <div className="inline-block">
                        {item.title && (
                          <h3 className="font-playfair text-2xl font-normal text-[#072D42] mb-2">
                            {item.title}
                          </h3>
                        )}
                        <p className="font-inter text-lg font-light text-[#072D42]/80 leading-relaxed">
                          {item.description}
                        </p>
                      </div>
                    </div>
                    
                    {/* Punto central */}
                    <div className="flex-shrink-0 w-4 h-4 rounded-full bg-[#072D42] border-4 border-white shadow-lg z-10"></div>
                    
                    {/* Año */}
                    <div className="w-1/5 pl-8 text-left">
                      <span className="font-playfair text-3xl font-normal text-[#072D42]">
                        {item.year}
                      </span>
                    </div>
                  </>
                ) : (
                  <>
                    {/* Lado derecho - años impares */}
                    <div className="w-1/5 pr-8 text-right">
                      <span className="font-playfair text-3xl font-normal text-[#072D42]">
                        {item.year}
                      </span>
                    </div>
                    
                    {/* Punto central */}
                    <div className="flex-shrink-0 w-4 h-4 rounded-full bg-[#072D42] border-4 border-white shadow-lg z-10"></div>
                    
                    {/* Contenido */}
                    <div className="w-2/5 pl-8 text-left">
                      <div className="inline-block">
                        {item.title && (
                          <h3 className="font-playfair text-2xl font-normal text-[#072D42] mb-2">
                            {item.title}
                          </h3>
                        )}
                        <p className="font-inter text-lg font-light text-[#072D42]/80 leading-relaxed">
                          {item.description}
                        </p>
                      </div>
                    </div>
                  </>
                )}
              </div>

              {/* Contenedor para móvil */}
              <div className="flex md:hidden items-start w-full pl-16">
                {/* Punto */}
                <div className="absolute left-8 top-2 w-3 h-3 rounded-full bg-[#072D42] border-2 border-white shadow-md z-10"></div>
                
                <div className="space-y-2">
                  {/* Año */}
                  <span className="font-playfair text-2xl font-normal text-[#072D42] block">
                    {item.year}
                  </span>
                  
                  {/* Título (si existe) */}
                  {item.title && (
                    <h3 className="font-playfair text-xl font-normal text-[#072D42]">
                      {item.title}
                    </h3>
                  )}
                  
                  {/* Descripción */}
                  <p className="font-inter text-base font-light text-[#072D42]/80 leading-relaxed">
                    {item.description}
                  </p>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  ),
};

const allSections = [...mainSections, howItStartedSection];
const SCROLL_OFFSET = 9.375;

// Estilos de fuentes
const fontStyles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,500;0,600;0,700;1,400&family=Montserrat:ital,wght@0,100;0,200;0,300;0,400;0,500;0,600;0,700;1,100;1,200;1,300;1,400&family=Inter:wght@100;200;300;400;500;600;700&display=swap');
  
  .font-playfair {
    font-family: 'Playfair Display', serif;
  }
  
  .font-montserrat {
    font-family: 'Montserrat', sans-serif;
  }
  
  .font-inter {
    font-family: 'Inter', sans-serif;
  }
`;

const AboutUsPage = () => {
  const [active, setActive] = useState(allSections[0].id);
  const [revealedSections, setRevealedSections] = useState({});
  const sectionRefs = useRef({});
  const [isHeaderShrunk, setIsHeaderShrunk] = useState(false);
  const [scrollY, setScrollY] = useState(0);
  const tickingRef = useRef(false);

  // Insertar estilos en el head del documento
  useEffect(() => {
    const styleElement = document.createElement('style');
    styleElement.textContent = fontStyles;
    document.head.appendChild(styleElement);
    
    return () => {
      document.head.removeChild(styleElement);
    };
  }, []);

  // ⚡ OPTIMIZADO: Scroll con throttling
  useEffect(() => {
    const handleScroll = () => {
      setIsHeaderShrunk(window.scrollY > 100);
      
      if (!tickingRef.current) {
        requestAnimationFrame(() => {
          setScrollY(window.scrollY);
          tickingRef.current = false;
        });
        tickingRef.current = true;
      }
    };
    
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // ⚡ OPTIMIZADO: IntersectionObserver más eficiente
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            setActive(entry.target.id);
            setRevealedSections(prev => ({ ...prev, [entry.target.id]: true }));
          }
        });
      },
      { 
        root: null, 
        threshold: 0.3,
        rootMargin: "-10% 0px -10% 0px"
      },
    );

    allSections.forEach((s) => {
      const el = sectionRefs.current[s.id];
      if (el) observer.observe(el);
    });
    
    return () => observer.disconnect();
  }, []);

  const scrollTo = (e, id) => {
    e.preventDefault();
    const el = sectionRefs.current[id];
    if (!el) return;
    
    const elementPosition = el.getBoundingClientRect().top + window.scrollY;
    const offsetPosition = elementPosition - (SCROLL_OFFSET * 16);
    
    window.scrollTo({ top: offsetPosition, behavior: "smooth" });
    setActive(id);
  };

  const parallaxStyle = {
    transform: `translate3d(0, ${scrollY * 0.4}px, 0)`
  };

  // Componente para el icono de fondo a la derecha (solo para mainSections)
  const BackgroundIcon = ({ icon: Icon, className = "" }) => {
    return (
      <div className={`absolute right-4 top-1/2 -translate-y-1/2 flex items-center justify-center pointer-events-none ${className}`}>
        <Icon className="w-32 h-32 md:w-48 md:h-48 opacity-10 text-[#072D42] group-hover:text-white transition-colors duration-500" />
      </div>
    );
  };

  // Componente para el Aside con diseño de media rueda
  const WheelAside = ({ position = "left" }) => {
    const totalSections = allSections.length;
    const activeIndex = allSections.findIndex(s => s.id === active);
    
    return (
      <aside className={`hidden lg:block lg:w-1/6 sticky top-40 ${position === 'left' ? 'order-first' : 'order-last'}`}>
        <div className="relative">
          {/* Media rueda de fondo */}
          <div className={`absolute top-1/2 -translate-y-1/2 ${
            position === 'left' ? 'left-0' : 'right-0'
          } w-32 h-64 overflow-hidden pointer-events-none`}>
            <div className={`w-64 h-64 rounded-full border-2 border-[#072D42]/20 relative ${
              position === 'left' ? '-left-32' : '-right-32'
            }`}>
              {/* Líneas radiales */}
              {allSections.map((_, index) => {
                const angle = (index * 180) / (totalSections - 1);
                const isActiveLine = index === activeIndex;
                return (
                  <div
                    key={index}
                    className={`absolute top-1/2 left-1/2 w-px h-16 origin-top ${
                      isActiveLine ? 'bg-[#072D42]' : 'bg-[#072D42]/20'
                    }`}
                    style={{
                      transform: `rotate(${position === 'left' ? angle : -angle}deg)`,
                      transformOrigin: 'bottom center'
                    }}
                  />
                );
              })}
            </div>
          </div>

          {/* Contenido de navegación */}
          <nav className="relative z-10 flex flex-col gap-2 pl-8">
            {allSections.map((s, index) => {
              const isActive = active === s.id;
              const isActiveWheel = index === activeIndex;
              
              return (
                <a
                  key={s.id}
                  href={`#${s.id}`}
                  onClick={(e) => scrollTo(e, s.id)}
                  className={`
                    relative group flex items-center gap-4 py-4 px-4 transition-all duration-500 ease-out
                    rounded-r-lg border border-l-0 border-[#9298A6]/30 bg-white/80 backdrop-blur-sm
                    hover:bg-[#072D42]/5 hover:border-[#072D42]/40
                    ${isActive ? 'bg-[#072D42]/10 border-[#072D42]/50 shadow-lg' : ''}
                    ${position === 'right' ? 'flex-row-reverse text-right rounded-l-lg rounded-r-none border-r-0 border-l' : ''}
                    transform ${position === 'left' ? 'hover:translate-x-2' : 'hover:-translate-x-2'}
                  `}
                >
                  {/* Indicador de sección activa */}
                  <div className={`
                    absolute top-1/2 -translate-y-1/2 w-2 h-8 rounded-full transition-all duration-500
                    ${position === 'left' ? '-left-1' : '-right-1'}
                    ${isActiveWheel ? 'bg-[#072D42] scale-100' : 'bg-[#072D42]/30 scale-50'}
                  `} />
                  
                  {/* Icono */}
                  <div className={`
                    flex items-center justify-center w-8 h-8 rounded-full transition-all duration-500
                    ${isActive 
                      ? 'bg-[#072D42] text-white scale-110' 
                      : 'bg-white text-[#072D42] scale-100 border border-[#072D42]/20'
                    }
                    group-hover:scale-105 group-hover:bg-[#072D42] group-hover:text-white
                  `}>
                    <s.icon className="w-4 h-4" />
                  </div>
                  
                  {/* Texto - Solo se muestra completo en la sección activa */}
                  <div className={`
                    transition-all duration-500 overflow-hidden
                    ${isActive ? 'max-w-32 opacity-100' : 'max-w-0 opacity-0'}
                    group-hover:max-w-32 group-hover:opacity-100
                  `}>
                    <span className={`
                      font-montserrat text-sm font-light tracking-wider whitespace-nowrap
                      ${isActive ? 'text-[#072D42] font-medium' : 'text-[#072D42]/70'}
                    `}>
                      {s.title}
                    </span>
                  </div>
                  
                  {/* Número de orden - Solo visible cuando el texto está oculto */}
                  <div className={`
                    absolute -top-1 -right-1 w-5 h-5 rounded-full flex items-center justify-center text-xs
                    transition-all duration-300
                    ${isActive 
                      ? 'bg-[#072D42] text-white scale-100' 
                      : 'bg-[#072D42]/10 text-[#072D42]/50 scale-75'
                    }
                    ${isActive ? 'opacity-0' : 'opacity-100'}
                    group-hover:opacity-0
                  `}>
                    {index + 1}
                  </div>
                </a>
              );
            })}
          </nav>
          
          {/* Indicador central de la rueda */}
          <div className={`
            absolute top-1/2 -translate-y-1/2 w-4 h-4 rounded-full bg-[#072D42] border-2 border-white shadow-lg
            transition-all duration-700 ease-out
            ${position === 'left' ? 'left-16' : 'right-16'}
            ${allSections.findIndex(s => s.id === active) >= 0 ? 'scale-100' : 'scale-0'}
          `} />
        </div>
      </aside>
    );
  };

  return (
    <div className="bg-[#FAF8F5] text-[#072D42] min-h-screen font-sans [&_a]:no-underline [&_a:hover]:no-underline">
      {/* HEADER CON EFECTO PARALLAX OPTIMIZADO */}
      <div className="h-[20vh] min-h-[25rem] max-h-[50rem] mb-9 overflow-hidden relative">
        <header className="relative h-full">
          <div 
            className="absolute inset-0 w-full h-full"
            style={parallaxStyle}
          >
            <img 
              src="/media/historiapage/salarB.jpg"
              alt="Fondo del Archivo Histórico Empresarial Boliviano"
              className="w-full h-full object-cover"
            />
            <div className="absolute inset-0 bg-black/45"></div>
          </div>
          
          <div className="relative z-30 p-20 lg:p-48 text-white h-full flex flex-col justify-center">
            {/* TÍTULO PRINCIPAL CON FUENTE ELEGANTE */}
            <h1 className="font-playfair text-5xl lg:text-9xl font-normal leading-[0.9] tracking-tight mb-4 text-white">
              Nosotros
            </h1>
            
            {/* SUBTÍTULO CON FUENTE EMPRESARIAL */}
            <div className="mb-6">
              <h2 className="font-montserrat text-2xl lg:text-3xl font-light tracking-[0.2em] uppercase text-white/95 mb-3">
                Archivo Histórico Empresarial
              </h2>
              <div className="h-px w-32 bg-white/70 mb-4"></div>
            </div>
            
            {/* TEXTO DESCRIPTIVO CON FUENTE MODERNA */}
            <p className="font-inter text-xl lg:text-2xl font-extralight tracking-wide max-w-2xl text-white/90 leading-relaxed">
              Registrando la evolución del sector empresarial boliviano y preservando legados de más de 40 años.
            </p>
          </div>
        </header>
      </div>

      <main className="px-10 py-0">
        {/* NAVEGACIÓN MÓVIL - SOLO EN MÓVIL */}
        <div className="block lg:hidden mb-8">
          <nav className="flex flex-row gap-2 overflow-x-auto py-4">
            {allSections.map((s) => (
              <a
                key={s.id}
                href={`#${s.id}`}
                onClick={(e) => scrollTo(e, s.id)}
                className={`
                  relative text-left py-3 px-4 transition-colors duration-200 whitespace-nowrap
                  rounded-lg border border-[#9298A6]/30 bg-white/10
                  hover:bg-[#9298A6]/10
                  ${
                    active === s.id 
                      ? 'bg-[#9298A6]/20 font-medium'
                      : 'font-light opacity-80 hover:opacity-100'
                  }
                `}
              >
                <span className="tracking-widest text-sm text-[#072D42]">{s.title}</span>
              </a>
            ))}
          </nav>
        </div>

        <div className="flex flex-col lg:flex-row gap-8 lg:items-start">
          {/* ASIDE IZQUIERDO CON MEDIA RUEDA */}
          <WheelAside position="left" />

          {/* CONTENIDO PRINCIPAL */}
          <section className="w-full lg:w-4/6 flex flex-col gap-20">
            {mainSections.map((s) => (
              <div
                key={s.id}
                id={s.id}
                ref={(el) => (sectionRefs.current[s.id] = el)}
                className={`
                  scroll-mt-24 bg-white rounded-xl shadow-md border border-[#072D42]/20 hover:border-[#072D42] hover:shadow-lg 
                  overflow-hidden group hover:bg-[#072D42]
                  transform transition-all duration-500 ease-out relative
                  ${revealedSections[s.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
                `}
              >
                {/* ICONO DE FONDO A LA DERECHA - SOLO PARA MAIN SECTIONS */}
                <BackgroundIcon icon={s.icon} />
                
                <div className={`transition-opacity duration-300 relative z-10 ${active === s.id ? "opacity-100" : "opacity-80"}`}>
                  <div className="flex flex-col md:flex-row">
                    {/* IMAGEN A LA IZQUIERDA - 35% SIN PADDING */}
                    {s.image && (
                      <div className="md:w-[35%] flex order-1 md:order-1 overflow-hidden">
                        <img 
                          src={s.image} 
                          alt={s.displayTitle} 
                          className="w-full h-full object-cover rounded-l-xl md:rounded-r-none transform group-hover:scale-105 transition-transform duration-700 ease-out" 
                        />
                      </div>
                    )}
                    
                    {/* TEXTO A LA DERECHA - 65% CON PADDING - CON ANIMACIONES MEJORADAS */}
                    <div className={s.image ? 'md:w-[65%] order-2 md:order-2 p-8 md:p-12 lg:p-16 text-center md:text-left relative z-20' : 'w-full order-2 p-8 md:p-12 lg:p-16 text-center md:text-left relative z-20'}>
                      <div className="mb-8 flex flex-col items-center md:items-start overflow-hidden">
                        <div className="flex items-center gap-3 mb-4 flex-col md:flex-row w-full">
                          <s.icon className="w-6 h-6 text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform group-hover:scale-110 flex-shrink-0" />
                          
                          {/* TÍTULO CON FUENTE ELEGANTE */}
                          <h2 className="font-playfair text-3xl lg:text-4xl font-normal tracking-wide text-[#072D42] group-hover:text-white transition-all duration-500 ease-out transform translate-y-0 group-hover:-translate-y-1">
                            {s.displayTitle}
                          </h2>
                        </div>
                        
                        {/* LÍNEA DIVISORIA CON ANIMACIÓN */}
                        <div className="h-px w-20 bg-[#072D42] group-hover:bg-white transition-all duration-500 ease-out transform origin-left md:ml-9 mx-auto md:mx-0 group-hover:scale-x-150"></div>
                      </div>
                      
                      {/* TEXTO CON FUENTE MODERNA - MANTIENE EL COLOR AZUL ORIGINAL */}
                      <div className="font-inter text-lg leading-relaxed font-light tracking-wide text-[#072D42]/95 group-hover:text-white/95 transition-all duration-700 ease-out transform translate-x-0 group-hover:translate-x-2 max-w-prose mx-auto md:mx-0 text-justify md:text-left relative z-30">
                        {s.body}
                      </div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
            
            {/* Sección "Nuestra Historia" CORREGIDA */}
            <div 
              id={howItStartedSection.id}
              ref={(el) => (sectionRefs.current[howItStartedSection.id] = el)}
              className={`
                scroll-mt-24 bg-white rounded-xl shadow-md border border-[#072D42]/20 p-8 md:p-12 lg:p-16
                transform transition-all duration-700 ease-out
                ${revealedSections[howItStartedSection.id] ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-8'}
              `}
            >
              <div className="mb-8 text-center md:text-left">
                <div className="flex items-center gap-3 mb-4 flex-col md:flex-row justify-center md:justify-start">
                  <howItStartedSection.icon className="w-6 h-6 text-[#072D42]" />
                  <h2 className="font-playfair text-3xl lg:text-4xl font-normal tracking-wide text-[#072D42]">
                    {howItStartedSection.displayTitle}
                  </h2>
                </div>
                <div className="h-px w-20 bg-[#072D42] mx-auto md:mx-0"></div>
              </div>
              <div className="font-inter">
                {howItStartedSection.body}
              </div>
            </div>
          </section>

          {/* ASIDE DERECHO CON MEDIA RUEDA */}
          <WheelAside position="right" />
        </div>

        <footer className="mt-24 pt-8 border-t border-[#072D42]/20 text-center max-w-5xl mx-auto">
          <p className="text-sm font-light tracking-wide text-[#072D42]/60 font-montserrat">
            © {new Date().getFullYear()} Archivo Histórico Empresarial Boliviano
          </p>
        </footer>
      </main>
    </div>
  );
};

export default AboutUsPage;
